    // Async command methods

    /// <summary>Send LockDoor command (0x0000).</summary>
    public Task<InvokeResponse> LockDoorAsync(
        byte[]? pINCode = default,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0000, tlv => { if (pINCode != null) tlv.AddOctetString(0, pINCode); }, ct);

    /// <summary>Send UnlockDoor command (0x0001).</summary>
    public Task<InvokeResponse> UnlockDoorAsync(
        byte[]? pINCode = default,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0001, tlv => { if (pINCode != null) tlv.AddOctetString(0, pINCode); }, ct);

    /// <summary>Send UnlockWithTimeout command (0x0003).</summary>
    public Task<InvokeResponse> UnlockWithTimeoutAsync(
        ushort timeout,
        byte[]? pINCode = default,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0003, tlv =>
        {
            tlv.AddUInt16(0, timeout);
            if (pINCode != null) tlv.AddOctetString(1, pINCode);
        }, ct);

    /// <summary>Send SetWeekDaySchedule command (0x000B).</summary>
    public Task<InvokeResponse> SetWeekDayScheduleAsync(
        byte weekDayIndex,
        ushort userIndex,
        DaysMaskMap daysMask,
        byte startHour,
        byte startMinute,
        byte endHour,
        byte endMinute,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x000B, tlv =>
        {
            tlv.AddUInt8(0, weekDayIndex);
            tlv.AddUInt16(1, userIndex);
            tlv.AddUInt8(2, (byte)daysMask);
            tlv.AddUInt8(3, startHour);
            tlv.AddUInt8(4, startMinute);
            tlv.AddUInt8(5, endHour);
            tlv.AddUInt8(6, endMinute);
        }, ct);

    /// <summary>Send GetWeekDaySchedule command (0x000C).</summary>
    public Task<InvokeResponse> GetWeekDayScheduleAsync(
        byte weekDayIndex,
        ushort userIndex,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x000C, tlv =>
        {
            tlv.AddUInt8(0, weekDayIndex);
            tlv.AddUInt16(1, userIndex);
        }, ct);

