    /// <summary>Send SetCredential command (0x0022).</summary>
    public Task<InvokeResponse> SetCredentialAsync(
        DataOperationTypeEnum operationType,
        CredentialStruct credential,
        byte[] credentialData,
        ushort? userIndex,
        UserStatusEnum userStatus,
        UserTypeEnum userType,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0022, tlv =>
        {
            tlv.AddUInt8(0, (byte)operationType);
            WriteCredentialStruct(tlv, 1, credential);
            tlv.AddOctetString(2, credentialData);
            if (userIndex != null) tlv.AddUInt16(3, userIndex.Value);
            tlv.AddUInt8(4, (byte)userStatus);
            tlv.AddUInt8(5, (byte)userType);
        }, ct);

    /// <summary>Send GetCredentialStatus command (0x0024).</summary>
    public Task<InvokeResponse> GetCredentialStatusAsync(
        CredentialStruct credential,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0024, tlv => { WriteCredentialStruct(tlv, 0, credential); }, ct);

    /// <summary>Send ClearCredential command (0x0026).</summary>
    public Task<InvokeResponse> ClearCredentialAsync(
        CredentialStruct credential,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0026, tlv => { WriteCredentialStruct(tlv, 0, credential); }, ct);

